mapper.select:
SELECT il.id, i.name AS item_name, i.category, i.spec, cs.slot_no, il.quantity, il.total_weight, il.operation_type, il.status, il.operator_no, il.operator_name, COALESCE(il.operator_name, il.operator_no, il.stored_by, il.removed_by) AS operator_display, COALESCE(il.stored_at, il.removed_at, il.created_at) AS operated_at FROM item_ledger il LEFT JOIN item i ON il.item_id = i.id AND i.deleted = 0 LEFT JOIN cabinet_slot cs ON il.slot_id = cs.id AND cs.deleted = 0 WHERE il.deleted = 0
AND il.cabinet_id = #{cabinetId}
AND il.operation_type = #{operationType}
AND il.status = #{status}
AND i.category = #{category}
ORDER BY COALESCE(il.stored_at, il.removed_at, il.created_at) DESC

SELECT SUM(total_weight) FROM item_ledger
WHERE cabinet_id = #{cabinetId}
  AND slot_id = #{slotId}
  AND status = 0
  AND deleted = 0
